import React, {createContext, type PropsWithChildren, type ReactNode, useRef} from 'react';
import type {IMainContextProps, IMainContextValues} from "@lmb-it/kitsconcerto-types";
import {BrowserRouter} from 'react-router-dom';
import {PrimeReactProvider} from 'primereact/api';
import '../Theme'
import {AdminLayout, AuthLayout} from "../../app-shell";
import LocaleContextProvider from "../Locale";
import ThemeContext, {KitsThemeProvider} from "../Theme";
import DialogProvider from "../DialogContext";
import PermissionsProvider from "../PermissionsContext";
import {useMediaQuery} from "react-responsive";
import '../../assets/custom_style.scss'
import 'primeicons/primeicons.css';
import 'primereact/resources/primereact.css';

export const MainContext = createContext<IMainContextValues>({} as IMainContextValues);

const MainContextProvider = ({
                                 renderRouter=false,
                                 children,
                                 theme,
                                 kitsTheme,
                                 onLogOut,
                                 nonAuthRoutes,
                                 menuItems,
                                 userAvatar,
                                 permissions,
                                 logo,
                                 languages,
                                 defaultLanguage = 'en',
                                 authedRoutes,
                                 onChangeLanguage,
                                 ref
                             }: PropsWithChildren<IMainContextProps>) => {

    const isSmall = useMediaQuery({
        maxWidth: 991
    })
    // To check if the device is a tablet
    const isTablet = useMediaQuery({
        minWidth: 768,
        maxWidth: 1023
    });

// To check if the device is a desktop
    const isDesktop = useMediaQuery({
        minWidth: 1024
    });

// To check if the device is in landscape mode
    const isLandscape = useMediaQuery({
        orientation: "landscape"
    });

// To check if the device is in portrait mode
    const isPortrait = useMediaQuery({
        orientation: "portrait"
    });

    const mq = {
        isSmall,
        isTablet,
        isDesktop,
        isLandscape,
        isPortrait
    }
    const headerRef = useRef<any>(null);
    const appendToHeader = (element: ReactNode) => {
        if (headerRef.current) {
            headerRef.current.appendToHeader(element)
        }
    }

    const authLayout = renderRouter && !!nonAuthRoutes && nonAuthRoutes.length > 0 && authedRoutes?.length == 0
    const adminLayout = renderRouter && !!authedRoutes && authedRoutes.length > 0 && nonAuthRoutes?.length == 0

    return (
        <BrowserRouter>
            <MainContext.Provider value={{logo, onLogOut, appendToHeader, menuItems, userAvatar, mq}}>
                <PrimeReactProvider value={{pt: theme}}>
                    <KitsThemeProvider theme={kitsTheme}>
                        <ThemeContext theme={theme}>
                            <LocaleContextProvider defaultLanguage={defaultLanguage} languages={languages}
                                                   onChangeLanguage={onChangeLanguage}>
                                <DialogProvider>
                                    <PermissionsProvider roles={permissions}>
                                        {authLayout && <AuthLayout routes={nonAuthRoutes}/>}
                                        {adminLayout && <AdminLayout routes={authedRoutes} headerRef={headerRef}/>}
                                        {children}
                                    </PermissionsProvider>
                                </DialogProvider>
                            </LocaleContextProvider>
                        </ThemeContext>
                    </KitsThemeProvider>
                </PrimeReactProvider>
            </MainContext.Provider>
        </BrowserRouter>
    );
};

export default MainContextProvider;
